"use strict";(globalThis.webpackChunkdocs=globalThis.webpackChunkdocs||[]).push([[114],{8502(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"ohada-lib-v1-stable-release","metadata":{"permalink":"/fr/blog/ohada-lib-v1-stable-release","editUrl":"https://github.com/Drc-Mind/ohda-lib/tree/main/docs/blog/2026-02-16-launching-ohada-lib.md","source":"@site/blog/2026-02-16-launching-ohada-lib.md","title":"@drcmind/ohada-lib v1.0.0 \u2014 First Stable Release","description":"We are thrilled to announce the official launch of @drcmind/ohada-lib v1.0.0 \u2014 First Stable Release, the first developer-first TypeScript library designed for the SYSCOHADA accounting framework.","date":"2026-02-16T00:00:00.000Z","tags":[{"inline":true,"label":"launch","permalink":"/fr/blog/tags/launch"},{"inline":true,"label":"ohada","permalink":"/fr/blog/tags/ohada"},{"inline":true,"label":"typescript","permalink":"/fr/blog/tags/typescript"}],"readingTime":1.06,"hasTruncateMarker":false,"authors":[{"name":"Marcellin Tacite","title":"Author of Ohada Lib","url":"https://github.com/marcellintacite","socials":{"github":"https://github.com/marcellintacite"},"imageURL":"https://github.com/marcellintacite.png","key":"tacite","page":null}],"frontMatter":{"slug":"ohada-lib-v1-stable-release","title":"@drcmind/ohada-lib v1.0.0 \u2014 First Stable Release","authors":["tacite"],"tags":["launch","ohada","typescript"]},"unlisted":false},"content":"We are thrilled to announce the official launch of **@drcmind/ohada-lib v1.0.0 \u2014 First Stable Release**, the first developer-first TypeScript library designed for the SYSCOHADA accounting framework.\\n\\n### The Problem: Accounting is Hard for Developers\\nIntegrating accounting logic into business applications has historically been a nightmare. Developers are forced to become amateur accountants, memorizing account codes like `701`, `601`, and `4431`, and manually balancing debits and credits. This lead to bugs, compliance issues, and slow development cycles.\\n\\n### The Solution: @drcmind/ohada-lib\\n**@drcmind/ohada-lib** changes this dynamic. Instead of thinking in accounts, you think in **Business Events**.\\n\\nWant to record a sale with a discount and immediate bank payment?\\n```typescript\\nohada.recordSale({\\n  amount: 1000000,\\n  label: \\"Large Order\\",\\n  financialDiscount: { percentage: 2 },\\n  payment: { method: \'bank\', amount: 1156400 }\\n});\\n```\\n\\nThe library handles the rest, generating a fully balanced, SYSCOHADA-compliant journal entry ready for your ledger.\\n\\n### Key Features at Launch\\n- **Direct Accounting Verbs**: `recordSale`, `recordPurchase`, `recordExpense`.\\n- **Smart Adjustments**: Automatic handling of transport, customs, and escomptes.\\n- **Multi-Locale Support**: English and French out of the box.\\n- **Type-Safe API**: Never guess what an input should look like again.\\n\\n### What\'s Next?\\nWe are actively working on expanding the library to support inventory management, payroll modules, and automated tax reporting.\\n\\nExplore the [documentation](/docs/intro) to get started today!"}]}}')}}]);